WyDA/profile-displayphoto-shrink_200_200/profile-displayphoto-shrink_200_200/0/1517260226118?e=1778112000&v=beta&t=_jyPUXfpihjZ3N_lL-JgWhFIGVnF6XfYsbOKM9kOH5o", "publicIdentifier": "chris-oakes-3b52a125", "recommendations/0/context": "Chris worked with Michael but they were at different companies", "recommendations/0/date": "September 17, 2015", "recommendations/0/description": "Michael Pritchard is a highly creative person with strong business and administration skills\nHe is reliable and and professional and my experience whilst working together was enlightening and stimulating\n", "recommendations/0/name": "Michael Pritchard", "recommendations/0/subtitle": "Founder of Heliconia (Bali, Bangkok)", "recommendations/0/url": "https://www.linkedin.com/in/michaelheliconia/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAYl1k8BfXyiu3VaPUsSOkqcq05uZth1GLM", "recommendations/1/context": "Chris was senior to Elie but didn't manage Elie directly", "recommendations/1/date": "January 10, 2014", "recommendations/1/description": "Elie is a young dynamic member of our team with strong knowledge and experience in many areas of our business\nHe is a very energised and focused member of the team and sees positives first in every instance. He aims high and I believe strongly that he will achieve his goals and targets in his career. His contribution was very good for our business - I wish him well for the future", "recommendations/1/name": "Elie  Vischel ", "recommendations/1/subtitle": "Chief Technology Officer @ Ardentis", "recommendations/1/url": "https://www.linkedin.com/in/elievischel/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAA_qyWUBuHYCmpjcLMmX7eP94jdi1oG_EYE", "recommendations/2/context": "Chris managed Frank directly", "recommendations/2/date": "August 19, 2013", "recommendations/2/description": "Frank has a strong understanding of quality service in general but specifically for the Luxury market. He applies a systematic set of processes to build a service culture within his properties resulting in a very personalised delivery.Frank also drives the training culture so as to embed the consistency of delivery into the team and business. It was a pleasure working with Frank.", "recommendations/2/name": "Frank Wesselhoefft", "recommendations/2/subtitle": "General Manager and Hotel & Gastronomy Consultant", "recommendations/2/url": "https://www.linkedin.com/in/frank-wesselhoefft-a8378a4/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAADTpYMBVeSksV0ZPZQgW96SlFOMd2BPPrI", "recommendations/3/context": "Chris was senior to Sabrina but didn't manage Sabrina directly", "recommendations/3/date": "March 12, 2013", "recommendations/3/description": "Sabrina Weitner played a significant role for Petchey leisure that stimulated sales for all Six Resorts totalling in excess of 1000 bedrooms.\nHer wide experience of On line travel agents and travel partners was an exceptional component in the success of the business which is a market leader in Portugal and Spain. Sabrina is a thorough professional and an asset to any company that employs her", "recommendations/3/name": "Sabrina Weitner", "recommendations/3/subtitle": "Market Manager Portugal at Expedia Group", "recommendations/3/url": "https://www.linkedin.com/in/sabrina-weitner-39b0298/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAFtYOcBkaM2BzPoyjy95rfT0OxNB8GsSJY", "recommendations/4/context": "Chris worked with Anwen on the same team", "recommendations/4/date": "April 2, 2012", "recommendations/4/description": "Anwen is a highly professional person with a clear and sytematic approach to her work. During her time at Six Senses Anwen clarified and professionalised a number systems and processes relating to the company's on line presence and commercial strategy. This ranged from Website,SEO,Social media and overall on line positioning. I hope to have the opportunity of working with Anwen again in the future", "recommendations/4/name": "Anwen Parry Kawada", "recommendations/4/subtitle": "Chief Marketing Officer (CMO)", "recommendations/4/url": "https://www.linkedin.com/in/anwenparry/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAAQ96wBHEEfLJt13Rk3t6VZj_zZBGTRQIY", "recommendations/5/context": "Chris worked with Anand on the same team", "recommendations/5/date": "January 20, 2012", "recommendations/5/description": "I have had the pleasure of working with Anand for close to 4years.\nDuring this dynamic and challenging time for Six Senses, Anand has been a pillar of strength.\nHis calm demeanour is complemented by a broad and deep knowledge of Human resources on the International stage\nHe is solution focused and a strong team player.", "recommendations/5/name": "Anand Rao", "recommendations/5/subtitle": "CEO - Owner at The Barn B & B, Walla Walla", "recommendations/5/url": "https://www.linkedin.com/in/anand-rao-7735278/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAGAUYcBCeSjvpyphGX2iOMEIG6om17uJPk", "recommendations/6/context": "Chris worked with Lionel on the same team", "recommendations/6/date": "January 11, 2012", "recommendations/6/description": "Lionel has been a colleague of mine for 8 years and has proven himself to be a strong business manager in challenging business environments.Lionel uses quality and consistency to deliver on commercial targets. He is well respected by his employees and peers and leads from the front.\nHis strong Food and Beverage background is evident in the businesses he manages.", "recommendations/6/name": "Lionel Valla", "recommendations/6/subtitle": "A seasoned and innovative hotelier dedicated to crafting unforgettable experiences for each stakeholder by strategically developing teams to enhance service excellence and drive exceptional financial performance.", "recommendations/6/url": "https://www.linkedin.com/in/lionelvalla/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAAFskLgBKn0LbxoCuPHTTt9FBFyKt1xBPBA", "recommendations/7/context": "Chris worked with Alasdair on the same team", "reco